    auto buffer = create_test_buffer(54321, "alice", {50, 75, 90}, "some metadata");

    PacketInfo info = extract_packet_info(buffer);

    EXPECT_EQ(54321, info.packet_id);
    EXPECT_EQ("alice", info.username);
}

