    std::cout << "\n--- Deallocating blocks (internally uses push()) ---" << std::endl;

    for (size_t i = 0; i < 3; ++i) {
        allocator.deallocate(blocks[i]);
        std::cout << "Deallocated block " << i << " -> active: " 
                  << allocator.storage_active_count << std::endl;
    }

    // Phase 3: Reallocate - will pop from free list (reusing deallocated blocks)
    std::cout << "\n--- Reallocating (pop reuses freed blocks) ---" << std::endl;

    for (size_t i = 0; i < 3; ++i) {
        auto* block = allocator.allocate();
        *block = i * 200;
        blocks[i] = block;
        std::cout << "Reallocated block " << i << " -> active: " 
                  << allocator.storage_active_count << std::endl;
