    std::cout << "  Total allocs: " << allocator.total_allocs << std::endl;
    std::cout << "  Total deallocs: " << allocator.total_deallocs << std::endl;

    std::cout << "\n=== Free List Behavior Summary ===" << std::endl;
    std::cout << "• push(): Adds freed blocks to the head of the free list" << std::endl;
    std::cout << "• pop(): Removes and returns blocks from the free list head" << std::endl;
    std::cout << "• This provides O(1) allocation/deallocation performance" << std::endl;
    std::cout << "• Deallocated blocks are reused in LIFO order (stack behavior)" << std::endl;
}
