template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    if (from == to) {
        return value;
    }

    // Handle all possible conversions
    if (from == std::endian::little) {
        if (to == std::endian::big) {
            return hexi::conditional_reverse<std::endian::little, std::endian::big>(value);
        } else if (to == std::endian::native) {
            return hexi::conditional_reverse<std::endian::little, std::endian::native>(value);
        }
    } else if (from == std::endian::big) {
        if (to == std::endian::little) {
            return hexi::conditional_reverse<std::endian::big, std::endian::little>(value);
        } else if (to == std::endian::native) {
            return hexi::conditional_reverse<std::endian::big, std::endian::native>(value);
        }
    } else if (from == std::endian::native) {
        if (to == std::endian::little) {
            return hexi::conditional_reverse<std::endian::native, std::endian::little>(value);
        } else if (to == std::endian::big) {
            return hexi::conditional_reverse<std::endian::native, std::endian::big>(value);
        }
    }

    return value;
}
```

