#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open the file for reading using file_buffer
    hexi::file_buffer file(file_path.string().c_str(), "rb");

    // Allocate vector to store the header data
    std::vector<uint8_t> header(header_size);

    // Read the first header_size bytes from the file
    file.read(reinterpret_cast<char*>(header.data()), header_size);

    // Rewind the file position back to the beginning
    // This ensures the read pointer is not advanced for subsequent operations
    file.rewind();

    return header;
}

