    // Read the count of elements
    uint32_t count;
    reader >> count;

    // Create the result vector and reserve space
    std::vector<uint32_t> result;
    result.reserve(count);

    // Read each element from the stream
    for (uint32_t i = 0; i < count; ++i) {
        uint32_t value;
        reader >> value;
        result.push_back(value);
    }

    return result;
}
