    std::size_t header_position = buffer.write_ptr();

    // Write header placeholder (0) - reserve space for header
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(uint32_t));

    // Write some body data (demonstrating the pattern)
    // In real usage, this would be actual payload data
    std::byte body_data[] = {std::byte{0x01}, std::byte{0x02}, std::byte{0x03}, std::byte{0x04}};
    buffer.write(body_data, sizeof(body_data));

    // Save current position after writing body
    std::size_t end_position = buffer.write_ptr();

    // Seek back to header position using absolute seek (from begin)
    buffer.write_seek(hexi::buffer_seek::begin, header_position);

    // Update header with actual value
    buffer.write(&header_value, sizeof(uint32_t));

    // Seek back to end position to continue writing if needed
    buffer.write_seek(hexi::buffer_seek::begin, end_position);
}

