using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned type for proper bit operations
    using unsigned_type = std::make_unsigned_t<T>;
    unsigned_type unsigned_value = static_cast<unsigned_type>(value);

    // Encode using varint format: 7 bits data + 1 bit continuation
    do {
        std::uint8_t byte = unsigned_value & 0x7F; // Extract lower 7 bits
        unsigned_value >>= 7; // Shift to next 7 bits

        if (unsigned_value != 0) {
            byte |= 0x80; // Set MSB to indicate more bytes follow
        }

        writer << byte; // Write the byte
        bytes_written++;
    } while (unsigned_value != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using unsigned_type = std::make_unsigned_t<T>;
    unsigned_type result = 0;
    int shift = 0;

    // Decode varint format
    while (true) {
        std::uint8_t byte;
        reader >> byte; // Read one byte

        // Extract the 7 data bits and add to result
        result |= static_cast<unsigned_type>(byte & 0x7F) << shift;

        // Check if this is the last byte (MSB == 0)
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7; // Move to next 7-bit group
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
