#include <gtest/gtest.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(PeekAndConsume, PeekHeaderWithoutReading) {
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    Header original;
    original.magic = 0x12345678;
    original.version = 0xABCD;

    adaptor.write(&original.magic, sizeof(original.magic));
    adaptor.write(&original.version, sizeof(original.version));

    // Peek at header
    Header peeked = peek_header_without_reading(buffer);

    EXPECT_EQ(original.magic, peeked.magic);
    EXPECT_EQ(original.version, peeked.version);

    // Verify we can still read the data after peeking
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    Header read_header;
    read_adaptor.read(&read_header.magic, sizeof(read_header.magic));
    read_adaptor.read(&read_header.version, sizeof(read_header.version));

    EXPECT_EQ(original.magic, read_header.magic);
    EXPECT_EQ(original.version, read_header.version);
}

TEST(PeekAndConsume, PeekThenConditionallyRead) {
    std::vector<uint8_t> buffer = {1, 2, 3, 4, 5};

    auto result = peek_then_conditionally_read(buffer);

    // Should read all data since first byte is non-zero
    EXPECT_EQ(buffer.size(), result.size());
    EXPECT_EQ(buffer, result);
}

TEST(PeekAndConsume, PeekThenSkip) {
    std::vector<uint8_t> buffer = {0, 1, 2, 3, 4}; // First byte is zero

    auto result = peek_then_conditionally_read(buffer);

    // Should not read data since first byte is zero
    EXPECT_TRUE(result.empty());
}

TEST(PeekAndConsume, MultiplePeeks) {
    std::vector<uint8_t> buffer = {10, 20, 30, 40};
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    // Peek multiple times - read pointer shouldn't advance
    uint8_t val1 = 0, val2 = 0, val3 = 0;

    read_adaptor.copy(&val1, 1);
    EXPECT_EQ(10, val1);
    EXPECT_EQ(4, read_adaptor.size());

    read_adaptor.copy(&val2, 1);
    EXPECT_EQ(10, val2); // Same value, pointer didn't move
    EXPECT_EQ(4, read_adaptor.size());

    read_adaptor.copy(&val3, 1);
    EXPECT_EQ(10, val3); // Still same value
    EXPECT_EQ(4, read_adaptor.size());

    // Now actually read
    uint8_t consumed = 0;
    read_adaptor.read(&consumed, 1);
    EXPECT_EQ(10, consumed);
    EXPECT_EQ(3, read_adaptor.size());
}

