    for (size_t i = 0; i < original.temperatures.size(); ++i) {
        EXPECT_FLOAT_EQ(original.temperatures[i], deserialized.temperatures[i]);
    }
    EXPECT_DOUBLE_EQ(original.pressure, deserialized.pressure);
}

